import{_ as a,c as e,l as n,a as r,t,a4 as p,o as i}from"./chunks/framework.CzsDe1xi.js";const C=JSON.parse('{"title":"容器运行时接口（CRI）","description":"","frontmatter":{"title":"容器运行时接口（CRI）"},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/cri.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/cri.md","lastUpdated":1709020051000}'),l={name:"doc/DevOps/Kubernetes/基础/cri.md"},o={id:"frontmatter-title",tabindex:"-1"},c=n("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),u=p(`<p>容器运行时接口（Container Runtime Interface），简称 CRI。CRI 中定义了 <strong>容器</strong> 和 <strong>镜像</strong> 的服务的接口，因为容器运行时与镜像的生命周期是彼此隔离的，因此需要定义两个服务。该接口使用 <a href="https://developers.google.com/protocol-buffers/" target="_blank" rel="noreferrer">Protocol Buffer</a>，基于 <a href="https://grpc.io/" target="_blank" rel="noreferrer">gRPC</a>，在 Kubernetes v1.10 + 版本中是在 <code>pkg/kubelet/apis/cri/runtime/v1alpha2</code> 的 <code>api.proto</code> 中定义的。</p><h2 id="cri-架构" tabindex="-1">CRI 架构 <a class="header-anchor" href="#cri-架构" aria-label="Permalink to &quot;CRI 架构&quot;">​</a></h2><p>Container Runtime 实现了 CRI gRPC Server，包括 <code>RuntimeService</code> 和 <code>ImageService</code>。该 gRPC Server 需要监听本地的 Unix socket，而 kubelet 则作为 gRPC Client 运行。</p><h2 id="启用-cri" tabindex="-1">启用 CRI <a class="header-anchor" href="#启用-cri" aria-label="Permalink to &quot;启用 CRI&quot;">​</a></h2><p>除非集成了 rktnetes，否则 CRI 都是被默认启用了，从 Kubernetes 1.7 版本开始，旧的预集成的 docker CRI 已经被移除。</p><p>要想启用 CRI 只需要在 kubelet 的启动参数重传入此参数：<code>--container-runtime-endpoint</code> 远程运行时服务的端点。当前 Linux 上支持 unix socket，windows 上支持 tcp。例如：<code>unix:///var/run/dockershim.sock</code>、 <code>tcp://localhost:373</code>，默认是 <code>unix:///var/run/dockershim.sock</code>，即默认使用本地的 docker 作为容器运行时。</p><h2 id="cri-接口" tabindex="-1">CRI 接口 <a class="header-anchor" href="#cri-接口" aria-label="Permalink to &quot;CRI 接口&quot;">​</a></h2><p>Kubernetes 1.9 中的 CRI 接口在 <code>api.proto</code> 中的定义如下：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>// Runtime service defines the public APIs for remote container runtimes</span></span>
<span class="line"><span>service RuntimeService {</span></span>
<span class="line"><span>    // Version returns the runtime name, runtime version, and runtime API version.</span></span>
<span class="line"><span>    rpc Version (VersionRequest) returns (VersionResponse) {}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // RunPodSandbox creates and starts a pod-level sandbox. Runtimes must ensure</span></span>
<span class="line"><span>    //the sandbox is in the ready state on success.</span></span>
<span class="line"><span>    rpc RunPodSandbox (RunPodSandboxRequest) returns (RunPodSandboxResponse) {}</span></span>
<span class="line"><span>    // StopPodSandbox stops any running process that is part of the sandbox and</span></span>
<span class="line"><span>    //reclaims network resources (e.g., IP addresses) allocated to the sandbox.</span></span>
<span class="line"><span>    // If there are any running containers in the sandbox, they must be forcibly</span></span>
<span class="line"><span>    //terminated.</span></span>
<span class="line"><span>    // This call is idempotent, and must not return an error if all relevant</span></span>
<span class="line"><span>    //resources have already been reclaimed. kubelet will call StopPodSandbox</span></span>
<span class="line"><span>    //at least once before calling RemovePodSandbox. It will also attempt to</span></span>
<span class="line"><span>    //reclaim resources eagerly, as soon as a sandbox is not needed. Hence,</span></span>
<span class="line"><span>    //multiple StopPodSandbox calls are expected.</span></span>
<span class="line"><span>    rpc StopPodSandbox (StopPodSandboxRequest) returns (StopPodSandboxResponse) {}</span></span>
<span class="line"><span>    // RemovePodSandbox removes the sandbox. If there are any running containers</span></span>
<span class="line"><span>    //in the sandbox, they must be forcibly terminated and removed.</span></span>
<span class="line"><span>    // This call is idempotent, and must not return an error if the sandbox has</span></span>
<span class="line"><span>    //already been removed.</span></span>
<span class="line"><span>    rpc RemovePodSandbox (RemovePodSandboxRequest) returns (RemovePodSandboxResponse) {}</span></span>
<span class="line"><span>    // PodSandboxStatus returns the status of the PodSandbox. If the PodSandbox is not</span></span>
<span class="line"><span>    //present, returns an error.</span></span>
<span class="line"><span>    rpc PodSandboxStatus (PodSandboxStatusRequest) returns (PodSandboxStatusResponse) {}</span></span>
<span class="line"><span>    // ListPodSandbox returns a list of PodSandboxes.</span></span>
<span class="line"><span>    rpc ListPodSandbox (ListPodSandboxRequest) returns (ListPodSandboxResponse) {}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // CreateContainer creates a new container in specified PodSandbox</span></span>
<span class="line"><span>    rpc CreateContainer (CreateContainerRequest) returns (CreateContainerResponse) {}</span></span>
<span class="line"><span>    // StartContainer starts the container.</span></span>
<span class="line"><span>    rpc StartContainer (StartContainerRequest) returns (StartContainerResponse) {}</span></span>
<span class="line"><span>    // StopContainer stops a running container with a grace period (i.e., timeout).</span></span>
<span class="line"><span>    // This call is idempotent, and must not return an error if the container has</span></span>
<span class="line"><span>    //already been stopped.</span></span>
<span class="line"><span>    // TODO: what must the runtime do after the grace period is reached?</span></span>
<span class="line"><span>    rpc StopContainer (StopContainerRequest) returns (StopContainerResponse) {}</span></span>
<span class="line"><span>    // RemoveContainer removes the container. If the container is running, the</span></span>
<span class="line"><span>    //container must be forcibly removed.</span></span>
<span class="line"><span>    // This call is idempotent, and must not return an error if the container has</span></span>
<span class="line"><span>    //already been removed.</span></span>
<span class="line"><span>    rpc RemoveContainer (RemoveContainerRequest) returns (RemoveContainerResponse) {}</span></span>
<span class="line"><span>    // ListContainers lists all containers by filters.</span></span>
<span class="line"><span>    rpc ListContainers (ListContainersRequest) returns (ListContainersResponse) {}</span></span>
<span class="line"><span>    // ContainerStatus returns status of the container. If the container is not</span></span>
<span class="line"><span>    //present, returns an error.</span></span>
<span class="line"><span>    rpc ContainerStatus (ContainerStatusRequest) returns (ContainerStatusResponse) {}</span></span>
<span class="line"><span>    // UpdateContainerResources updates ContainerConfig of the container.</span></span>
<span class="line"><span>    rpc UpdateContainerResources (UpdateContainerResourcesRequest) returns (UpdateContainerResourcesResponse) {}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // ExecSync runs a command in a container synchronously.</span></span>
<span class="line"><span>    rpc ExecSync (ExecSyncRequest) returns (ExecSyncResponse) {}</span></span>
<span class="line"><span>    // Exec prepares a streaming endpoint to execute a command in the container.</span></span>
<span class="line"><span>    rpc Exec (ExecRequest) returns (ExecResponse) {}</span></span>
<span class="line"><span>    // Attach prepares a streaming endpoint to attach to a running container.</span></span>
<span class="line"><span>    rpc Attach (AttachRequest) returns (AttachResponse) {}</span></span>
<span class="line"><span>    // PortForward prepares a streaming endpoint to forward ports from a PodSandbox.</span></span>
<span class="line"><span>    rpc PortForward (PortForwardRequest) returns (PortForwardResponse) {}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // ContainerStats returns stats of the container. If the container does not</span></span>
<span class="line"><span>    //exist, the call returns an error.</span></span>
<span class="line"><span>    rpc ContainerStats (ContainerStatsRequest) returns (ContainerStatsResponse) {}</span></span>
<span class="line"><span>    // ListContainerStats returns stats of all running containers.</span></span>
<span class="line"><span>    rpc ListContainerStats (ListContainerStatsRequest) returns (ListContainerStatsResponse) {}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // UpdateRuntimeConfig updates the runtime configuration based on the given request.</span></span>
<span class="line"><span>    rpc UpdateRuntimeConfig (UpdateRuntimeConfigRequest) returns (UpdateRuntimeConfigResponse) {}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // Status returns the status of the runtime.</span></span>
<span class="line"><span>    rpc Status (StatusRequest) returns (StatusResponse) {}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// ImageService defines the public APIs for managing images.</span></span>
<span class="line"><span>service ImageService {</span></span>
<span class="line"><span>    // ListImages lists existing images.</span></span>
<span class="line"><span>    rpc ListImages (ListImagesRequest) returns (ListImagesResponse) {}</span></span>
<span class="line"><span>    // ImageStatus returns the status of the image. If the image is not</span></span>
<span class="line"><span>    //present, returns a response with ImageStatusResponse.Image set to</span></span>
<span class="line"><span>    //nil.</span></span>
<span class="line"><span>    rpc ImageStatus (ImageStatusRequest) returns (ImageStatusResponse) {}</span></span>
<span class="line"><span>    // PullImage pulls an image with authentication config.</span></span>
<span class="line"><span>    rpc PullImage (PullImageRequest) returns (PullImageResponse) {}</span></span>
<span class="line"><span>    // RemoveImage removes the image.</span></span>
<span class="line"><span>    // This call is idempotent, and must not return an error if the image has</span></span>
<span class="line"><span>    //already been removed.</span></span>
<span class="line"><span>    rpc RemoveImage (RemoveImageRequest) returns (RemoveImageResponse) {}</span></span>
<span class="line"><span>    // ImageFSInfo returns information of the filesystem that is used to store images.</span></span>
<span class="line"><span>    rpc ImageFsInfo (ImageFsInfoRequest) returns (ImageFsInfoResponse) {}}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br><span class="line-number">58</span><br><span class="line-number">59</span><br><span class="line-number">60</span><br><span class="line-number">61</span><br><span class="line-number">62</span><br><span class="line-number">63</span><br><span class="line-number">64</span><br><span class="line-number">65</span><br><span class="line-number">66</span><br><span class="line-number">67</span><br><span class="line-number">68</span><br><span class="line-number">69</span><br><span class="line-number">70</span><br><span class="line-number">71</span><br><span class="line-number">72</span><br><span class="line-number">73</span><br><span class="line-number">74</span><br><span class="line-number">75</span><br><span class="line-number">76</span><br><span class="line-number">77</span><br><span class="line-number">78</span><br><span class="line-number">79</span><br><span class="line-number">80</span><br><span class="line-number">81</span><br><span class="line-number">82</span><br><span class="line-number">83</span><br><span class="line-number">84</span><br><span class="line-number">85</span><br><span class="line-number">86</span><br><span class="line-number">87</span><br><span class="line-number">88</span><br></div></div><p>这其中包含了两个 gRPC 服务：</p><ul><li><strong>RuntimeService</strong>：容器和 Sandbox 运行时管理。</li><li><strong>ImageService</strong>：提供了从镜像仓库拉取、查看、和移除镜像的 RPC。</li></ul><h2 id="当前支持的-cri-后端" tabindex="-1">当前支持的 CRI 后端 <a class="header-anchor" href="#当前支持的-cri-后端" aria-label="Permalink to &quot;当前支持的 CRI 后端&quot;">​</a></h2><p>我们最初在使用 Kubernetes 时通常会默认使用 Docker 作为容器运行时，其实从 Kubernetes 1.5 开始已经支持 CRI，通过 CRI 接口可以指定使用其它容器运行时作为 Pod 的后端，目前支持 CRI 的后端有：</p><ul><li><a href="https://github.com/kubernetes-incubator/cri-o" target="_blank" rel="noreferrer">cri-o</a>：cri-o 是 Kubernetes 的 CRI 标准的实现，并且允许 Kubernetes 间接使用 OCI 兼容的容器运行时，可以把 cri-o 看成 Kubernetes 使用 OCI 兼容的容器运行时的中间层。</li><li><a href="https://github.com/containerd/cri-containerd" target="_blank" rel="noreferrer">cri-containerd</a>：基于 <a href="https://github.com/containerd/containerd" target="_blank" rel="noreferrer">Containerd</a> 的 Kubernetes CRI 实现</li><li><a href="https://coreos.com/rkt/" target="_blank" rel="noreferrer">rkt</a>：由 CoreOS 主推的用来跟 docker 抗衡的容器运行时</li><li><a href="https://github.com/kubernetes/frakti" target="_blank" rel="noreferrer">frakti</a>：基于 hypervisor 的 CRI</li><li><a href="https://www.docker.com" target="_blank" rel="noreferrer">docker</a>：Kuberentes 最初就开始支持的容器运行时，目前还没完全从 kubelet 中解耦，Docker 公司同时推广了 <a href="https://www.opencontainers.org/" target="_blank" rel="noreferrer">OCI</a> 标准</li></ul><p>CRI 是由 <a href="https://kubernetes.slack.com/archives/sig-node" target="_blank" rel="noreferrer">SIG-Node</a> 来维护的。</p><h2 id="当前通过-cri-o-间接支持-cri-的后端" tabindex="-1">当前通过 CRI-O 间接支持 CRI 的后端 <a class="header-anchor" href="#当前通过-cri-o-间接支持-cri-的后端" aria-label="Permalink to &quot;当前通过 CRI-O 间接支持 CRI 的后端&quot;">​</a></h2><p>当前同样存在一些只实现了 <a href="https://www.opencontainers.org/" target="_blank" rel="noreferrer">OCI</a> 标准的容器，但是它们可以通过 CRI-O 来作为 Kubernetes 的容器运行时。CRI-O 是 Kubernetes 的 CRI 标准的实现，并且允许 Kubernetes 间接使用 OCI 兼容的容器运行时。</p><ul><li><a href="https://github.com/clearcontainers" target="_blank" rel="noreferrer">Clear Containers</a>：由 Intel 推出的兼容 OCI 容器运行时，可以通过 CRI-O 来兼容 CRI。</li><li><a href="https://katacontainers.io/" target="_blank" rel="noreferrer">Kata Containers</a>：符合 OCI 规范，可以通过 CRI-O 或 <a href="https://github.com/containerd/cri" target="_blank" rel="noreferrer">Containerd CRI Plugin</a> 来兼容 CRI。</li><li><a href="https://github.com/google/gvisor" target="_blank" rel="noreferrer">gVisor</a>：由谷歌推出的容器运行时沙箱 (Experimental)，可以通过 CRI-O 来兼容 CRI。</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://sreeninet.wordpress.com/2017/02/11/kubernetes-cri-and-minikube/" target="_blank" rel="noreferrer">Kubernetes CRI and Minikube - sreeninet.wordpress.com</a></li><li><a href="https://projectatomic.io/blog/2017/02/crio-runtimes/" target="_blank" rel="noreferrer">CRI-O and Alternative Runtimes in Kubernetes - projectatomic.io</a></li><li><a href="https://www.infoq.cn/article/2017/02/Docker-Containerd-RunC/" target="_blank" rel="noreferrer">Docker、Containerd、RunC...：你应该知道的所有</a></li><li><a href="https://kubernetes.io/blog/2016/12/container-runtime-interface-cri-in-kubernetes/" target="_blank" rel="noreferrer">Introducing Container Runtime Interface (CRI) in Kubernetes - blog.kubernetes.io</a></li><li><a href="https://cri-o.io/" target="_blank" rel="noreferrer">cri-o 官网 - cri-o.io</a></li><li><a href="https://github.com/kata-containers/documentation/blob/master/design/architecture.md#kubernetes-support" target="_blank" rel="noreferrer">Kata Containers Architecture - github.com</a></li></ul>`,20);function b(s,m,d,h,R,g){return i(),e("div",null,[n("h1",o,[r(t(s.$frontmatter.title)+" ",1),c]),u])}const I=a(l,[["render",b]]);export{C as __pageData,I as default};
